sql:
SELECT COUNT(passenger_id) AS survived_count
FROM passengers
WHERE survived = 1;

SELECT AVG(fare) AS average_fare
FROM ticket_sales
WHERE voyage_id = 0;

SELECT survived
FROM passengers
WHERE age > 50 AND sex = 'male';

SELECT AVG(age) AS average_age
FROM passengers
WHERE nationality = 'British' AND survived = 1;

SELECT port_location, COUNT(port_name) AS number_of_ports
FROM port_info
GROUP BY port_location;

SELECT name, role, experience
FROM crew_members
WHERE experience > 10;

SELECT ship_name, AVG(ship_capacity) AS average_capacity
FROM voyages
GROUP BY ship_name;

external_knowledge:
- "typical cost for a ticket" refers to the average fare;
- "how many folks have boarded" corresponds to the count of ticket sales;
- "approximately how many crew members are involved" means the count of crew members.
